  1	import * as React from 'react';
  2	import { ODF_ADMIN } from '@odf/core/features';
  3	import {
  4	  EmptyBucketAlerts,
  5	  EmptyBucketResponse,
  6	} from '@odf/core/modals/s3-browser/delete-and-empty-bucket/EmptyBucketModal';
  7	import { S3ProviderType } from '@odf/core/types';
  8	import { useRefresh } from '@odf/shared/hooks';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import { getValidFilteredData } from '@odf/shared/utils';
 11	import {
 12	  ListPageBody,
 13	  ListPageCreateLink,
 14	  ListPageFilter,
 15	  ListPageHeader,
 16	  useListPageFilter,
 17	  useFlag,
 18	  useModal,
 19	} from '@openshift-console/dynamic-plugin-sdk';
 20	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 21	import { TFunction } from 'react-i18next';
 22	import {
 23	  Button,
 24	  ButtonVariant,
 25	  Flex,
 26	  FlexItem,
 27	  Label,
 28	  Card,
 29	  CardHeader,
 30	  CardTitle,
 31	  FormGroup,
 32	  TextContent,
 33	  Text,
 34	  TextVariants,
 35	} from '@patternfly/react-core';
 36	import { SyncAltIcon, InfoCircleIcon } from '@patternfly/react-icons';
 37	import { ActionsColumn, IAction } from '@patternfly/react-table';
 38	import { getBucketCreatePageRoute } from '../../../constants';
 39	import { BucketCrFormat } from '../../../types';
 40	import { LazyLoginModal } from '../../s3-common/components/LazyLogin';
 41	import {
 42	  useSystemInfo,
 43	  SystemInfoData,
 44	} from '../../s3-common/hooks/useSystemInfo';
 45	import { SetSecretRefWithStorage, ClientType } from '../../s3-common/types';
 46	import { S3Provider, S3Context } from '../s3-context';
 47	import { BucketsListTable } from './bucketListTable';
 48	import { BucketPagination } from './bucketPagination';
 49	
 50	type BucketInfo = [BucketCrFormat[], boolean, any];
 51	
 52	type BucketsListPageBodyProps = {
 53	  bucketInfo: BucketInfo;
 54	  setBucketInfo: React.Dispatch<React.SetStateAction<BucketInfo>>;
 55	};
 56	
 57	type StorageEndpointProps = {
 58	  s3Provider: S3ProviderType;
 59	  setS3Provider: React.Dispatch<React.SetStateAction<S3ProviderType>>;
 60	  systemInfo: SystemInfoData;
 61	};
 62	
 63	export const getAccountActionsItems = (
 64	  t: TFunction,
 65	  launcher: LaunchModal,
 66	  providerType: S3ProviderType,
 67	  logout: () => void,
 68	  setSecretRef: SetSecretRefWithStorage,
 69	  clientType?: ClientType
 70	): IAction[] => [
 71	  {
 72	    title: t('Sign in to another account'),
 73	    description: t('You will be signed out of this account.'),
 74	    onClick: () =>
 75	      launcher(LazyLoginModal, {
 76	        isOpen: true,
 77	        extraProps: {
 78	          providerType,
 79	          logout,
 80	          onLogin: setSecretRef,
 81	          type: clientType,
 82	        },
 83	      }),
 84	  },
 85	  {
 86	    title: t('Sign out'),
 87	    onClick: () => logout(),
 88	  },
 89	];
 90	
 91	export const getAcountBadge = (t: TFunction) => (
 92	  <Label color="green" icon={<InfoCircleIcon />}>
 93	    {t('Signed in with credentials')}
 94	  </Label>
 95	);
 96	
 97	const BucketsListPageBody: React.FC<BucketsListPageBodyProps> = ({
 98	  bucketInfo,
 99	  setBucketInfo,
100	}) => {
101	  const { t } = useCustomTranslation();
102	  const [fresh, triggerRefresh] = useRefresh();
103	  const [emptyBucketResponse, setEmptyBucketResponse] =
104	    React.useState<EmptyBucketResponse>({
105	      response: null,
106	      bucketName: '',
107	    });
108	
109	  const [buckets, loaded, loadError] = bucketInfo;
110	  const [allBuckets, filteredBuckets, onFilterChange] =
111	    useListPageFilter(buckets);
112	
113	  return (
114	    <ListPageBody>
115	      <EmptyBucketAlerts
116	        emptyBucketResponse={emptyBucketResponse}
117	        setEmptyBucketResponse={setEmptyBucketResponse}
118	        triggerRefresh={triggerRefresh}
119	      />
120	      <Flex className="pf-v6-u-mt-md">
121	        <Flex flex={{ default: 'flex_1' }}>
122	          <FlexItem className="pf-v6-u-mr-md">
123	            <ListPageFilter
124	              loaded={true}
125	              hideLabelFilter={true}
126	              nameFilterPlaceholder={t('Search a bucket by name')}
127	              data={getValidFilteredData(allBuckets)}
128	              onFilterChange={onFilterChange}
129	            />
130	          </FlexItem>
131	          <FlexItem>
132	            <Button
133	              data-test="bucket-list-sync-button"
134	              variant={ButtonVariant.plain}
135	              onClick={triggerRefresh}
136	              isDisabled={!fresh}
137	            >
138	              <SyncAltIcon />
139	            </Button>
140	          </FlexItem>
141	        </Flex>
142	        <Flex>
143	          <FlexItem>
144	            {fresh && <BucketPagination setBucketInfo={setBucketInfo} />}
145	          </FlexItem>
146	        </Flex>
147	      </Flex>
148	      {fresh && (
149	        <BucketsListTable
150	          allBuckets={allBuckets}
151	          filteredBuckets={filteredBuckets}
152	          loaded={loaded}
153	          error={loadError}
154	          setEmptyBucketResponse={setEmptyBucketResponse}
155	          triggerRefresh={triggerRefresh}
156	        />
157	      )}
158	    </ListPageBody>
159	  );
160	};
161	
162	const BucketsListPageContent: React.FC = () => {
163	  const { t } = useCustomTranslation();
164	  const [bucketInfo, setBucketInfo] = React.useState<BucketInfo>([
165	    [],
166	    false,
167	    undefined,
168	  ]);
169	
170	  const isAdmin = useFlag(ODF_ADMIN);
171	  const { s3Client, logout, setSecretRef } = React.useContext(S3Context);
172	  const launcher = useModal();
173	
174	  const providerType = s3Client.providerType as S3ProviderType;
175	
176	  return (
177	    <>
178	      <ListPageHeader
179	        title={t('Buckets')}
180	        helpText={t('Browse, upload, and manage objects in buckets.')}
181	        {...(!isAdmin ? { badge: getAcountBadge(t) } : {})}
182	      >
183	        <ListPageCreateLink to={getBucketCreatePageRoute(providerType)}>
184	          {t('Create bucket')}
185	        </ListPageCreateLink>
186	        {!isAdmin && (
187	          <ActionsColumn
188	            items={getAccountActionsItems(
189	              t,
190	              launcher,
191	              providerType,
192	              logout,
193	              setSecretRef
194	            )}
195	          />
196	        )}
197	      </ListPageHeader>
198	      <BucketsListPageBody
199	        bucketInfo={bucketInfo}
200	        setBucketInfo={setBucketInfo}
201	      />
202	    </>
203	  );
204	};
205	
206	const StorageEndpoint: React.FC<StorageEndpointProps> = ({
207	  s3Provider,
208	  setS3Provider,
209	  systemInfo = {},
210	}) => {
211	  const { t } = useCustomTranslation();
212	
213	  const onChange = (event: React.FormEvent<HTMLInputElement>) => {
214	    setS3Provider(event.currentTarget.id as S3ProviderType);
215	  };
216	
217	  // Only support secure (https) RGW endpoint (no http support)
218	  // In case both internal and external RGW are present (multi-cluster scenario), select internal only
219	  // No external RGW support yet (only internal)
220	  const isInternalRgw = Object.values(systemInfo || []).some(
221	    (info) =>
222	      info.isInternalMode && info.isRGWAvailable && info.rgwSecureEndpoint
223	  );
224	
225	  return (
226	    <FormGroup
227	      label={
228	        <TextContent className="pf-v6-u-mt-md">
229	          <Text component={TextVariants.h1}>{t('Storage endpoint')}</Text>
230	        </TextContent>
231	      }
232	      className="pf-v6-u-mx-lg"
233	    >
234	      <Flex direction={{ default: 'row' }}>
235	        <FlexItem>
236	          <Card
237	            id="mcg-s3"
238	            isSelectable
239	            isSelected={s3Provider === S3ProviderType.Noobaa}
240	          >
241	            <CardHeader
242	              selectableActions={{
243	                selectableActionId: S3ProviderType.Noobaa,
244	                selectableActionAriaLabelledby: 'mcg-s3-endpoint-selection',
245	                name: 'mcg-s3-endpoint-selection',
246	                variant: 'single',
247	                onChange,
248	              }}
249	            >
250	              <CardTitle>{t('MultiCloud Object Gateway (MCG)')}</CardTitle>
251	            </CardHeader>
252	          </Card>
253	        </FlexItem>
254	        <FlexItem>
255	          <Card
256	            id="rgw-s3"
257	            isSelectable
258	            isSelected={s3Provider === S3ProviderType.RgwInt}
259	            isDisabled={!isInternalRgw}
260	          >
261	            <CardHeader
262	              selectableActions={{
263	                selectableActionId: S3ProviderType.RgwInt,
264	                selectableActionAriaLabelledby: 'rgw-s3-endpoint-selection',
265	                name: 'rgw-s3-endpoint-selection',
266	                variant: 'single',
267	                onChange,
268	              }}
269	            >
270	              <CardTitle>{t('RADOS Object Gateway (RGW)')}</CardTitle>
271	            </CardHeader>
272	          </Card>
273	        </FlexItem>
274	      </Flex>
275	    </FormGroup>
276	  );
277	};
278	
279	const BucketsListPage: React.FC = () => {
280	  const [s3Provider, setS3Provider] = React.useState(S3ProviderType.Noobaa);
281	
282	  const { data: systemInfo, isLoading } = useSystemInfo();
283	
284	  return (
285	    <>
286	      <StorageEndpoint
287	        s3Provider={s3Provider}
288	        setS3Provider={setS3Provider}
289	        systemInfo={systemInfo}
290	      />
291	      <S3Provider loading={isLoading} s3Provider={s3Provider}>
292	        <BucketsListPageContent />
293	      </S3Provider>
294	    </>
295	  );
296	};
297	
298	export default BucketsListPage;

